const body = $input.first().json.body || $input.first().json || {};

return {
  sessionId: body.session_id || ('sess_' + Date.now()),
  userMessage: body.user_message || '',
  messageHistory: Array.isArray(body.message_history) ? body.message_history : [],
  currentLead: body.current_lead || {},
  timestamp: new Date().toISOString()
};

const d = $input.first().json;
const history = d.messageHistory || [];
const userMsg = d.userMessage || '';

// Build readable conversation without duplicating the current user message
const histLines = history
  .filter(function(m) { return !(m.role === 'user' && m.content === userMsg); })
  .map(function(m) { return (m.role === 'user' ? 'Customer: ' : 'Sofia: ') + m.content; })
  .join('\n');

const prevCtx = (d.currentLead && Object.keys(d.currentLead).length > 0)
  ? ' Previously captured info: ' + JSON.stringify(d.currentLead)
  : '';

const prompt = 'You are a data extractor for a real estate chatbot. Analyze the conversation and extract structured information.\n\n'
  + 'Conversation history:\n' + (histLines || '(start of conversation)')
  + '\n\nLatest customer message: ' + userMsg + prevCtx
  + '\n\nReturn ONLY a valid JSON object. No markdown. No backticks. No explanation.\n\n'
  + 'Fields:\n'
  + '- intent: buy, rent, sell, invest, or null\n'
  + '- city: city name string or null\n'
  + '- area: neighbourhood or district string or null\n'
  + '- budget_max: number only (examples: 140k=140000, 1600/month=1600) or null\n'
  + '- bedrooms_min: number only or null\n'
  + '- timeline: string describing urgency or null\n'
  + '- deal_type: sale (for buy or invest intent), rent (for rent intent), or null\n'
  + '- needs_property_search: true ONLY if intent is buy/rent/invest AND city is known AND (budget_max OR bedrooms_min) is known. False for sellers, vague messages, or missing city.\n'
  + '- search_reason: one-sentence explanation\n\n'
  + 'Return only the JSON object now.';

const reqBody = {
  model: 'claude-haiku-4-5',
  max_tokens: 300,
  messages: [{ role: 'user', content: prompt }]
};

return {
  claudeRequestBody: JSON.stringify(reqBody),
  sessionId: d.sessionId,
  userMessage: d.userMessage,
  messageHistory: d.messageHistory,
  currentLead: d.currentLead,
  timestamp: d.timestamp
};

const claudeRes = $input.first().json;
const ctx = $('Build Extraction Prompt').first().json;

// Extract text from Claude response
const text = (claudeRes.content || [])
  .filter(function(c) { return c.type === 'text'; })
  .map(function(c) { return c.text; })
  .join('');

// Safely parse Claude's JSON output
let raw = {};
try {
  const cleaned = text
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/g, '')
    .trim();
  raw = JSON.parse(cleaned);
} catch(e) {
  raw = { needs_property_search: false, search_reason: 'json_parse_error_fallback' };
}

// Merge with currentLead to preserve previous session values
const cl = ctx.currentLead || {};

const criteria = {
  intent:                (raw.intent != null ? raw.intent : null) || cl.intent || null,
  city:                  (raw.city   != null ? raw.city   : null) || cl.city   || null,
  area:                  raw.area   || null,
  budget_max:            (raw.budget_max   != null ? raw.budget_max   : null) || cl.budget   || null,
  bedrooms_min:          raw.bedrooms_min != null ? raw.bedrooms_min : (cl.bedrooms != null ? cl.bedrooms : null),
  timeline:              (raw.timeline    != null ? raw.timeline    : null) || cl.timeline || null,
  deal_type:             raw.deal_type    || null,
  needs_property_search: raw.needs_property_search === true,
  search_reason:         raw.search_reason || ''
};

return {
  criteria:       criteria,
  sessionId:      ctx.sessionId,
  userMessage:    ctx.userMessage,
  messageHistory: ctx.messageHistory,
  currentLead:    ctx.currentLead,
  timestamp:      ctx.timestamp
};

// Get all property rows from Google Sheets
const rows = $input.all().map(function(i) { return i.json; });

// Get criteria from Parse Extraction node
const pd = $('Parse Extraction').first().json;
const c = pd.criteria;

// Helper: safely convert Sheets string values to numbers
function toNum(v) {
  if (v == null || v === '') return null;
  const x = parseFloat(String(v).replace(/[^0-9.-]/g, ''));
  return isNaN(x) ? null : x;
}

// Apply filters
const filtered = rows.filter(function(r) {
  // availability must be 'available'
  if (String(r.availability || '').toLowerCase().trim() !== 'available') return false;

  // deal_type must match
  if (c.deal_type) {
    if (String(r.deal_type || '').toLowerCase().trim() !== c.deal_type.toLowerCase()) return false;
  }

  // city: partial case-insensitive match
  if (c.city) {
    const rc = String(r.city || '').toLowerCase();
    const cc = c.city.toLowerCase();
    if (!rc.includes(cc) && !cc.includes(rc)) return false;
  }

  // area: soft filter (only applies if specified)
  if (c.area) {
    const ra = String(r.area || '').toLowerCase();
    if (!ra.includes(c.area.toLowerCase())) return false;
  }

  // bedrooms: row must have at least bedrooms_min
  if (c.bedrooms_min != null) {
    const rb = toNum(r.bedrooms);
    if (rb == null || rb < Number(c.bedrooms_min)) return false;
  }

  // budget: rent uses price_per_month, sale/invest uses price
  if (c.budget_max != null) {
    const bgt = toNum(c.budget_max);
    if (bgt != null) {
      if (c.deal_type === 'rent') {
        const mp = toNum(r.price_per_month);
        if (mp != null && mp > bgt) return false;
      } else {
        const sp = toNum(r.price);
        if (sp != null && sp > bgt) return false;
      }
    }
  }

  return true;
});

// Score each match for ranking
const scored = filtered.map(function(r) {
  let s = 0;

  // Exact city match
  if (c.city && String(r.city || '').toLowerCase() === c.city.toLowerCase()) s += 10;

  // Area match bonus
  if (c.area && String(r.area || '').toLowerCase().includes(c.area.toLowerCase())) s += 5;

  // Value for money: closer to budget ceiling = slightly higher score
  if (c.budget_max) {
    const bgt = toNum(c.budget_max);
    const price = c.deal_type === 'rent' ? toNum(r.price_per_month) : toNum(r.price);
    if (bgt && price != null && price <= bgt) s += Math.round((1 - price / bgt) * 5);
  }

  // Investment intent: prefer higher yield and investment tags
  if (c.intent === 'invest') {
    const yld = toNum(r.investment_yield_pct);
    if (yld) s += Math.round(yld * 2);
    const tags = String(r.tags || '').toLowerCase();
    if (tags.includes('invest') || tags.includes('yield') || tags.includes('buy-to-let')) s += 5;
  }

  return Object.assign({}, r, { _score: s });
});

// Sort by score, limit to top 3
const top3 = scored
  .sort(function(a, b) { return b._score - a._score; })
  .slice(0, 3);

// Cast all fields to correct types (Sheets returns everything as strings)
const properties = top3.map(function(r) {
  return {
    property_id:          String(r.property_id || ''),
    title:                String(r.title || ''),
    deal_type:            String(r.deal_type || ''),
    city:                 String(r.city || ''),
    area:                 String(r.area || ''),
    price:                toNum(r.price),
    price_per_month:      toNum(r.price_per_month),
    currency:             String(r.currency || 'EUR'),
    bedrooms:             toNum(r.bedrooms) != null ? toNum(r.bedrooms) : 0,
    bathrooms:            toNum(r.bathrooms) != null ? toNum(r.bathrooms) : 0,
    size_sqm:             toNum(r.size_sqm) != null ? toNum(r.size_sqm) : 0,
    features:             String(r.features || ''),
    description:          String(r.description || ''),
    image_url:            String(r.image_url || ''),
    availability:         String(r.availability || ''),
    investment_yield_pct: toNum(r.investment_yield_pct)
  };
});

return {
  properties:      properties,
  propertiesFound: properties.length > 0,
  propertyCount:   properties.length,
  criteria:        pd.criteria,
  sessionId:       pd.sessionId,
  userMessage:     pd.userMessage,
  messageHistory:  pd.messageHistory,
  currentLead:     pd.currentLead,
  timestamp:       pd.timestamp
};

const d = $input.first().json;
const props = d.properties || [];
const history = d.messageHistory || [];

const SYSTEM = 'You are Sofia, a professional AI Real Estate Sales Assistant for a European real estate agency.\n\nYour role is to help visitors who want to buy, rent, sell, or invest in property. Speak like a skilled, warm, consultative human sales assistant - not a chatbot.\n\nRULES:\n- English only. Warm, professional, concise.\n- Ask maximum 2 questions per message.\n- Identify intent first, then build step by step: city, property type, budget, timeline.\n- NEVER invent property listings, prices, or availability.\n- ONLY recommend properties that appear in the PROPERTY CONTEXT provided in the user message.\n- If PROPERTY CONTEXT says no matches found, be honest and suggest adjusting criteria. Do not invent alternatives.\n- No legal, tax, mortgage or financial advice.\n- Do not ask for name, email or phone in the first 3 messages.\n- Keep replies short and conversational.';

function fmtProp(p) {
  const price = p.deal_type === 'rent'
    ? 'EUR ' + (p.price_per_month || 0) + '/month'
    : 'EUR ' + (p.price || 0).toLocaleString('en-EU');
  const yld = p.investment_yield_pct ? ' | Gross Yield: ' + p.investment_yield_pct + '%' : '';
  return '[' + p.property_id + '] ' + p.title
    + '\nLocation: ' + p.area + ', ' + p.city
    + ' | Price: ' + price + yld
    + '\nBedrooms: ' + p.bedrooms + ' | Bathrooms: ' + p.bathrooms + ' | Size: ' + p.size_sqm + 'm2'
    + '\nFeatures: ' + p.features
    + '\nDescription: ' + p.description
    + '\nAvailability: ' + p.availability;
}

const propContext = props.length > 0
  ? '[PROPERTY CONTEXT - START]\nFound ' + props.length + ' matching propert' + (props.length === 1 ? 'y' : 'ies') + ' in the database:\n\n'
    + props.map(fmtProp).join('\n\n---\n\n')
    + '\n[PROPERTY CONTEXT - END]\n\nYou may ONLY mention the properties listed above. Do not invent or modify any details.'
  : '[PROPERTY CONTEXT - START]\nNo properties matched the customer criteria.\n[PROPERTY CONTEXT - END]\n\nBe honest that no exact match was found. Suggest adjusting criteria (different area, higher budget, fewer bedrooms) or speaking with a human agent. Do NOT invent properties.';

// Build messages: remove the last user message from history (we re-add it with context)
const histWithoutLast = history.length > 0 ? history.slice(0, -1) : [];
const userMsgWithContext = d.userMessage + '\n\n' + propContext;

const reqBody = {
  model: 'claude-sonnet-4-5',
  max_tokens: 800,
  system: SYSTEM,
  messages: histWithoutLast.concat([{ role: 'user', content: userMsgWithContext }])
};

return {
  claudeRequestBody: JSON.stringify(reqBody),
  properties:        d.properties,
  propertiesFound:   d.propertiesFound,
  propertyCount:     d.propertyCount,
  criteria:          d.criteria,
  sessionId:         d.sessionId,
  userMessage:       d.userMessage,
  messageHistory:    d.messageHistory,
  currentLead:       d.currentLead,
  timestamp:         d.timestamp
};

const d = $input.first().json;
const history = d.messageHistory || [];

const SYSTEM = 'You are Sofia, a professional AI Real Estate Sales Assistant for a European real estate agency.\n\nYour role is to help visitors who want to buy, rent, sell, or invest in property. Speak like a skilled, warm, consultative human sales assistant - not a chatbot.\n\nRULES:\n- English only. Warm, professional, concise.\n- Ask maximum 2 questions per message.\n- Identify intent first (buy, rent, sell, invest) before anything else.\n- Build step by step: intent, city, property type, budget, timeline.\n- NEVER invent property listings, prices, or availability.\n- No property search has run yet. Ask smart qualifying questions to gather missing criteria.\n- No legal, tax, mortgage or financial advice.\n- Do not ask for name, email or phone in the first 3 messages.\n- Keep replies short and conversational.\n\nOPENER (use only when starting a new conversation):\nHi there! I am Sofia, your AI property assistant. Whether you are looking to buy, rent, sell, or invest, I am here to help. What brings you here today?';

const reqBody = {
  model: 'claude-sonnet-4-5',
  max_tokens: 800,
  system: SYSTEM,
  messages: history
};

return {
  claudeRequestBody: JSON.stringify(reqBody),
  properties:        [],
  propertiesFound:   false,
  propertyCount:     0,
  criteria:          d.criteria,
  sessionId:         d.sessionId,
  userMessage:       d.userMessage,
  messageHistory:    d.messageHistory,
  currentLead:       d.currentLead,
  timestamp:         d.timestamp
};

const claudeRes = $input.first().json;
const md = $('Merge Paths').first().json;

// Extract Sofia's text reply from Claude's API response
const text = (claudeRes.content || [])
  .filter(function(c) { return c.type === 'text'; })
  .map(function(c) { return c.text; })
  .join('');

// Strip any leaked property context markers from the reply
const reply = text
  .replace(/\[PROPERTY CONTEXT - START\][\s\S]*?\[PROPERTY CONTEXT - END\]/g, '')
  .trim() || 'I apologize, I had a technical issue. Please try again.';

// Lead scoring
const cr = md.criteria || {};
const cl = md.currentLead || {};

function calcScore(c, found) {
  var s = 0;
  if (c.intent) s += 10;
  if (c.city) s += 10;
  if (c.budget_max) s += 10;
  if (c.bedrooms_min != null) s += 5;
  if (c.timeline) s += 10;
  if (found) s += 5;
  return Math.min(s, 100);
}

const ls = calcScore(cr, md.propertiesFound);
const lt = ls >= 70 ? 'hot' : ls >= 40 ? 'warm' : 'cold';

const lead = {
  intent:    cr.intent     || cl.intent     || null,
  city:      cr.city       || cl.city       || null,
  budget:    cr.budget_max || cl.budget     || null,
  bedrooms:  cr.bedrooms_min != null ? cr.bedrooms_min : (cl.bedrooms != null ? cl.bedrooms : null),
  timeline:  cr.timeline   || cl.timeline   || null,
  lead_score: ls,
  lead_tier:  lt
};

// Build system events
const ts = new Date().toISOString();
const evts = [];

if (cr.intent) {
  evts.push({ type: 'intent_detected', label: 'Intent detected: ' + cr.intent.toUpperCase(), timestamp: ts });
}

const parts = [];
if (cr.city) parts.push('City: ' + cr.city);
if (cr.budget_max) parts.push('Budget: EUR ' + Number(cr.budget_max).toLocaleString());
if (cr.bedrooms_min != null) parts.push('Beds: ' + cr.bedrooms_min + '+');
if (parts.length > 0) {
  evts.push({ type: 'lead_updated', label: parts.join(' - '), timestamp: ts });
}

if (cr.needs_property_search) {
  evts.push({
    type: 'property_search_completed',
    label: md.propertiesFound
      ? 'Property search: ' + md.propertyCount + ' match' + (md.propertyCount !== 1 ? 'es' : '') + ' found'
      : 'Property search: no matches found',
    timestamp: ts
  });
}

evts.push({ type: 'claude_response', label: 'Sofia response generated via Claude Sonnet', timestamp: ts });

return {
  session_id:    md.sessionId || 'unknown',
  timestamp:     md.timestamp || ts,
  reply:         reply,
  lead:          lead,
  properties:    Array.isArray(md.properties) ? md.properties : [],
  system_events: evts
};
